var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"음? 넌 뭐야?","JPN":"うん？　お前は誰だ？","ENG":"Mm? Who are you?","TWN":"嗯？你是誰？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 저번에 바텐더 면접을 보기로 연락 드렸던 니콜 프라이머라고 합니다.","JPN":"はじめまして。バーテンダーの面接を受けに来た、ニコル・プライマーです。","ENG":"Nice to meet you. My name is Nicole Primer. I'm here for my bartender interview.","TWN":"你好，初次見面，我叫妮可·布萊伊莫，之前有打來說要應徵調酒師。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"바텐더 면접? 우리가 그런 걸 봤었나?","JPN":"バーテンダーの面接？　そんなのあったっけ？","ENG":"Bartender interview? Do we even do that sort of thing?","TWN":"應徵調酒師？有這回事嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"잠깐, 새로운 바텐더라면 보스 추천으로 온다던 프로 아냐?","JPN":"まて、新しいバーテンダーならボスの推薦で来るといったプロじゃないか？","ENG":"Wait, is she the new bartender? The pro, who came highly recommended by the Boss?","TWN":"等等，新來的調酒師，那不就是之前老大推薦的專家？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"아, 그 사람?","JPN":"ああ、例の？","ENG":"Oh, is she?","TWN":"喔～那個人喔？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"하지만 저렇게 밝은 인상일 줄은 몰랐는데……?","JPN":"だがこんな明るい印象だとは思わなかったが……","ENG":"But I didn't think she'd be such a cheerful sort...","TWN":"沒想到形象這麼……小清新？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"인상이 무슨 상관이야. 중요한 건 실력이지.","JPN":"印象なんて関係ないだろ。大事なのは実力だ。","ENG":"Who cares? What matters is her skills.","TWN":"人不可貌相啦，重點是實力！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(우와, 제가 사전에 공부했던 바텐더와는 조금 다른 분위기…)","JPN":"(わあ、私が以前勉強したバーテンダーとはちょっと違う雰囲気……)","ENG":"(Whoa, they're a bit different from the bartenders I imagined...)","TWN":"(哇，怎麼跟我在書上看到的調酒師感覺不太一樣…)"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(역시 책으로 배운 것과 현실은 조금 거리가 있네요.)","JPN":"(やっぱり本で学んだことと現実は少し違うみたいですね。)","ENG":"(I guess there is a gap between knowledge and reality.)","TWN":"(書本的知識和現實果然是有點落差的。)"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"당신 소문은 들었어. 조직에 들어온 지 얼마 안 돼서 보스에게 인정받았다지?","JPN":"あんたの噂は聞いたぜ。\\n組織に入ってすぐにボスから実力を認められたそうだな。","ENG":"I've heard things about you. You haven't been with us long, but you already managed to impress the Boss. Is that right?","TWN":"久仰大名，聽說你進到組織後沒多久，就很受到老大的重用是吧？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"蛤？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(소문? 조직? 보스?)","JPN":"(噂？　組織？　ボス？)","ENG":"(What things about me? With whom? Who's the Boss?)","TWN":"(什麼大名？組織？老大？)"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이 사람들 설마, 제가 구마회에서 왔다는 사실을 알고 있는 걸까요?)","JPN":"(この人たちはまさか、私が祓魔会から来た事実を知っているのでしょうか？)","ENG":"(Oh no, do they know I'm from the Exorcism Council?)","TWN":"(這些人該不會知道我是從驅魔會來的吧？)"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(자, 침착해요. 퇴마사가 아닌 바텐더 지망생으로서의 완벽한 연기를 보여주는 거예요.)","JPN":"(お、落ち着きましょう。エクソシストではなく、バーテンダーの卵としての完璧な演技を見せるのです。)","ENG":"(Calm down, Nicole. Right now, you're not an exorcist but a bartender. Act like it.)","TWN":"(先冷靜點，我現在是調酒師，不是驅魔師，我要展現出專業的態度。)"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"<color=#ffd34c>블랜딩</color> 실력이 꽤 좋다고 들었는데. 온 김에 우리 애들한테 시범 좀 보여 줘.","JPN":"<color=#ffd34c>ブレンド</color>の腕前がなかなかだと聞いたが、せっかくだし手本を見せてくれ。","ENG":"I've heard you're pretty good at <color=#ffd34c>blending</color>. Why don't you show us what you can do while you're here?","TWN":"我聽說你很會<color=#ffd34c>調製</color>，機會難得，不如你就示範一下給我們看吧！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? …네! 어떤 걸 만들어 볼까요?","JPN":"え？　……はい！　いいですよ、何を作りましょうか？","ENG":"Huh? ... Sure! What do you want me to make?","TWN":"什？ …好！要調什麼呢？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}}]`);export{e as default};